module.exports = {
    name: "autoplay",
    aliases: ["ap"],
    description: "Toggle automatic similar-song playback when queue ends.",
    usage: "autoplay <on|off|status>",

    async execute({ bot, message, args, reply }) {
        const mode = String(args[0] || "status").toLowerCase();

        const hasPremium = await bot.music.hasPremiumAccess(message.author.id).catch(() => false);
        if (!hasPremium) {
            await reply({
                title: "Premium Required",
                description: "Autoplay is available for vote premium and buy premium users only."
            });
            return;
        }

        if (!["on", "off", "status"].includes(mode)) {
            await reply({
                title: "Invalid Option",
                description: "Use `autoplay on`, `autoplay off`, or `autoplay status`."
            });
            return;
        }

const guildCooldowns = new Map();
const DISCONNECT_COOLDOWN_MS = 1200;

module.exports = {
    name: "disconnect",
    aliases: ["dc", "leave"],
    description: "Disconnect bot from voice channel.",
    usage: "disconnect",
    async execute({ bot, message, reply }) {
        const now = Date.now();
        const key = message.guild.id;
        const last = guildCooldowns.get(key) || 0;
        if (now - last < DISCONNECT_COOLDOWN_MS) {
            return;
        }
        guildCooldowns.set(key, now);

        const ok = await bot.music.disconnect(message.guild.id);
        if (!ok) {
            await reply({ title: "Not Connected", description: "No active voice connection." });
            return;
        }

        await reply({ title: "Disconnected", description: "Left voice channel." });
    }
};

